class TestStripEmbeddedImages:
    """Tests for _strip_embedded_images."""

    def test_strips_reference_style_base64_images(self):
        from calendar_fetcher.consolidator import _strip_embedded_images

        content = (
            "Some text\n"
            "[image1]: <data:image/png;base64,iVBORw0KGgoAAAAN...>\n"
            "More text\n"
        )
        result = _strip_embedded_images(content)
        assert "data:image" not in result
        assert "[image1]: [image removed]" in result
        assert "Some text" in result
        assert "More text" in result

    def test_strips_inline_base64_images(self):
        from calendar_fetcher.consolidator import _strip_embedded_images

        content = "Look at this ![chart](data:image/png;base64,abc123) here\n"
        result = _strip_embedded_images(content)
        assert "data:image" not in result
        assert "[image removed]" in result
        assert "Look at this" in result

    def test_preserves_normal_images(self):
        from calendar_fetcher.consolidator import _strip_embedded_images

        content = "![photo](https://example.com/img.png)\n"
        result = _strip_embedded_images(content)
        assert result == content

    def test_no_images_returns_unchanged(self):
        from calendar_fetcher.consolidator import _strip_embedded_images

        content = "Just plain text\nNo images here\n"
        result = _strip_embedded_images(content)
        assert result == content


class TestBuildMetadataHeader:
    """Tests for _build_metadata_header."""

    def test_basic_header(self):
        info = DocInfo(
            file_id="abc123",
            local_path=Path("/tmp/notes.md"),
            local_mtime=0.0,
            meeting_summary="Weekly Engineering Sync",
            meeting_start="2026-03-26T13:25:00-04:00",
            recurring=True,
            attendees=[
                {"displayName": "Alice", "responseStatus": "accepted"},
                {"displayName": "Bob", "responseStatus": "declined"},
            ],
        )
        header = _build_metadata_header(info)
        assert "Meeting: Weekly Engineering Sync" in header
        assert "Date: 2026-03-26 13:25" in header
        assert "Recurring: Yes" in header
        assert "Alice (accepted)" in header
        assert "~~Bob~~ (declined)" in header
        assert "Source: https://docs.google.com/document/d/abc123/edit" in header
        assert header.endswith("---\n")

    def test_not_recurring(self):
        info = DocInfo(
            file_id="xyz",
            local_path=Path("/tmp/notes.md"),
            local_mtime=0.0,
            meeting_summary="One-off",
            meeting_start="2026-03-26T10:00:00Z",
            recurring=False,
            attendees=[],
        )
        header = _build_metadata_header(info)
        assert "Recurring: No" in header

    def test_no_attendees(self):
        info = DocInfo(
            file_id="xyz",
            local_path=Path("/tmp/notes.md"),
            local_mtime=0.0,
            meeting_summary="Solo",
            meeting_start="2026-03-26T10:00:00Z",
            recurring=False,
            attendees=[],
        )
        header = _build_metadata_header(info)
        assert "Attendees:" in header

    def test_attendee_without_display_name(self):
        info = DocInfo(
            file_id="xyz",
            local_path=Path("/tmp/notes.md"),
            local_mtime=0.0,
            meeting_summary="Test",
            meeting_start="2026-03-26T10:00:00Z",
            recurring=False,
            attendees=[{"email": "user@example.com", "responseStatus": "accepted"}],
        )
        header = _build_metadata_header(info)
        assert "user@example.com (accepted)" in header


