class TestTabOperations:
    """Tests for Docs API tab operations (mocked)."""

    def test_read_existing_tabs(self):
        doc_response = {
            "tabs": [
                {"tabProperties": {"tabId": "t.abc", "title": "file_id_1"}},
                {"tabProperties": {"tabId": "t.def", "title": "file_id_2"}},
            ]
        }
        with patch("calendar_fetcher.consolidator.run_gws", return_value=doc_response):
            result = _read_existing_tabs("doc123")
        assert result == {"file_id_1": "t.abc", "file_id_2": "t.def"}

    def test_read_existing_tabs_empty_doc(self):
        with patch("calendar_fetcher.consolidator.run_gws", return_value={}):
            result = _read_existing_tabs("doc123")
        assert result == {}

    def test_create_tab(self):
        create_response = {
            "replies": [{"addDocumentTab": {"tabProperties": {"tabId": "t.new123"}}}]
        }
        insert_response = {"replies": [{}]}
        with patch(
            "calendar_fetcher.consolidator.run_gws_write",
            side_effect=[create_response, insert_response],
        ) as mock_write:
            tab_id = _create_tab("doc123", "file_id_abc", "Header\n---\nContent")
        assert tab_id == "t.new123"
        assert mock_write.call_count == 2
        first_json = mock_write.call_args_list[0][1]["json_body"]
        assert "addDocumentTab" in first_json["requests"][0]
        second_json = mock_write.call_args_list[1][1]["json_body"]
        assert (
            second_json["requests"][0]["insertText"]["endOfSegmentLocation"]["tabId"]
            == "t.new123"
        )

    def test_create_tab_chunks_large_content(self):
        """Verify large content is split into multiple insertText calls."""
        import calendar_fetcher.consolidator as mod

        create_response = {
            "replies": [{"addDocumentTab": {"tabProperties": {"tabId": "t.big"}}}]
        }
        insert_response = {"replies": [{}]}

        # Content larger than _MAX_TEXT_BYTES
        large_content = "x" * (mod._MAX_TEXT_BYTES + 1000)

        with patch(
            "calendar_fetcher.consolidator.run_gws_write",
            side_effect=[
                create_response,
                insert_response,
                insert_response,
            ],
        ) as mock_write:
            tab_id = _create_tab("doc123", "big_doc", large_content)

        assert tab_id == "t.big"
        # 1 create + 2 inserts (content split into 2 chunks)
        assert mock_write.call_count == 3

    def test_delete_tab(self):
        with patch(
            "calendar_fetcher.consolidator.run_gws_write",
            return_value={"replies": [{}]},
        ) as mock_write:
            _delete_tab("doc123", "t.old456")
        call_json = mock_write.call_args[1]["json_body"]
        assert call_json["requests"][0]["deleteTab"]["tabId"] == "t.old456"


class TestConsolidate:
    """Tests for the main consolidate function."""

    def test_creates_tabs_for_new_docs(self, populated_output_dir):
        doc_response = {"tabs": []}
        create_response = {
            "replies": [{"addDocumentTab": {"tabProperties": {"tabId": "t.new1"}}}]
        }
        insert_response = {"replies": [{}]}
        with (
            patch("calendar_fetcher.consolidator.run_gws", return_value=doc_response),
            patch(
                "calendar_fetcher.consolidator.run_gws_write",
                side_effect=[create_response, insert_response],
            ) as mock_write,
        ):
            consolidate(populated_output_dir, "output_doc_id")
        assert mock_write.call_count == 2

    def test_skips_unchanged_docs(self, populated_output_dir):
        md_file = populated_output_dir / "2026-03-26_weekly_notes_abc123.md"
        mtime = md_file.stat().st_mtime
        state = {
            "consolidate_state": {
                "last_run": "2026-04-03T15:00:00Z",
                "output_doc_id": "output_doc_id",
                "tabs": {
                    "abc123": {"tab_id": "t.existing", "source_mtime": str(mtime)}
                },
            }
        }
        with open(populated_output_dir / "fetcher-state.json", "w") as f:
            json.dump(state, f)
        doc_response = {
            "tabs": [{"tabProperties": {"tabId": "t.existing", "title": "abc123"}}]
        }
        with (
            patch("calendar_fetcher.consolidator.run_gws", return_value=doc_response),
            patch("calendar_fetcher.consolidator.run_gws_write") as mock_write,
        ):
            consolidate(populated_output_dir, "output_doc_id")
        mock_write.assert_not_called()

    def test_recreates_tab_for_changed_doc(self, populated_output_dir):
        state = {
            "consolidate_state": {
                "last_run": "2026-04-03T15:00:00Z",
                "output_doc_id": "output_doc_id",
                "tabs": {"abc123": {"tab_id": "t.old", "source_mtime": "0.0"}},
            }
        }
        with open(populated_output_dir / "fetcher-state.json", "w") as f:
            json.dump(state, f)
        doc_response = {
            "tabs": [{"tabProperties": {"tabId": "t.old", "title": "abc123"}}]
        }
        delete_response = {"replies": [{}]}
        create_response = {
            "replies": [{"addDocumentTab": {"tabProperties": {"tabId": "t.new1"}}}]
        }
        insert_response = {"replies": [{}]}
        with (
            patch("calendar_fetcher.consolidator.run_gws", return_value=doc_response),
            patch(
                "calendar_fetcher.consolidator.run_gws_write",
                side_effect=[delete_response, create_response, insert_response],
            ) as mock_write,
        ):
            consolidate(populated_output_dir, "output_doc_id")
        assert mock_write.call_count == 3

    def test_writes_state_after_consolidation(self, populated_output_dir):
        doc_response = {"tabs": []}
        create_response = {
            "replies": [{"addDocumentTab": {"tabProperties": {"tabId": "t.new1"}}}]
        }
        insert_response = {"replies": [{}]}
        with (
            patch("calendar_fetcher.consolidator.run_gws", return_value=doc_response),
            patch(
                "calendar_fetcher.consolidator.run_gws_write",
                side_effect=[create_response, insert_response],
            ),
        ):
            consolidate(populated_output_dir, "output_doc_id")
        with open(populated_output_dir / "fetcher-state.json") as f:
            full_state = json.load(f)
        cs = full_state["consolidate_state"]
        assert cs["output_doc_id"] == "output_doc_id"
        assert "abc123" in cs["tabs"]
        assert cs["tabs"]["abc123"]["tab_id"] == "t.new1"

    def test_no_docs_found(self, tmp_path):
        with (
            patch("calendar_fetcher.consolidator.run_gws") as mock_gws,
            patch("calendar_fetcher.consolidator.run_gws_write") as mock_write,
        ):
            consolidate(tmp_path, "output_doc_id")
        mock_gws.assert_not_called()
        mock_write.assert_not_called()
